<?php declare(strict_types=1); namespace Tests\Feature\FreshProduce; use App\Domains\FreshProduce\Models\FreshProduce; use Database\Factories\FreshProduce\FreshProduceFactory; use Tests\TestCase; final class FreshProduceTest extends TestCase { use \Illuminate\Foundation\Testing\DatabaseTransactions; public function test_can_create_produce(): void { $item = FreshProduceFactory::new()->create(['tenant_id' => 1]); $this->assertDatabaseHas('fresh_produces', ['id' => $item->id]); } public function test_premium_produce(): void { $item = FreshProduceFactory::new()->premium()->create(['tenant_id' => 1]); $this->assertEquals(2000, $item->quantity_grams); } public function test_budget_produce(): void { $item = FreshProduceFactory::new()->budget()->create(['tenant_id' => 1]); $this->assertEquals(250, $item->quantity_grams); } public function test_category(): void { $item = FreshProduceFactory::new()->create(['tenant_id' => 1, 'category' => 'fruits']); $this->assertEquals('fruits', $item->category); } public function test_freshness_guarantee(): void { $item = FreshProduceFactory::new()->create(['tenant_id' => 1]); $this->assertGreaterThan(0, $item->freshness_guarantee_hours); } public function test_harvest_date(): void { $item = FreshProduceFactory::new()->create(['tenant_id' => 1]); $this->assertNotNull($item->harvest_date); } }
